public protocol SecureCrypting {
    func encrypt<T: Encodable>(_ value: T) throws -> Data
    func decrypt<T: Decodable>(_ type: T.Type, from encryptedData: Data) throws -> T
}

public final class SecureCryptoManager: SecureCrypting {
    private let keyAlias = "com.example.bank.module.masterkey"
    private let encoder: JSONEncoder
    private let decoder: JSONDecoder

    public init() {
        self.encoder = JSONEncoder()
        self.decoder = JSONDecoder()
        self.encoder.dateEncodingStrategy = .iso8601
        self.decoder.dateDecodingStrategy = .iso8601
    }

    public func encrypt<T: Encodable>(_ value: T) throws -> Data {
        let key = try fetchOrCreateKey()
        let plain = try encoder.encode(value)
        do {
            let sealedBox = try AES.GCM.seal(plain, using: key)
            guard let combined = sealedBox.combined else {
                throw BankingError.encryptionFailure
            }
            return combined
        } catch {
            throw BankingError.encryptionFailure
        }
    }

    public func decrypt<T: Decodable>(_ type: T.Type, from encryptedData: Data) throws -> T {
        let key = try fetchOrCreateKey()
        do {
            let box = try AES.GCM.SealedBox(combined: encryptedData)
            let decrypted = try AES.GCM.open(box, using: key)
            return try decoder.decode(type, from: decrypted)
        } catch {
            throw BankingError.decryptionFailure
        }
    }

    private func fetchOrCreateKey() throws -> SymmetricKey {
        if let existing = try readKeychainData(account: keyAlias) {
            return SymmetricKey(data: existing)
        }

        let key = SymmetricKey(size: .bits256)
        let raw = key.withUnsafeBytes { Data($0) }
        try writeKeychainData(raw, account: keyAlias)
        return key
    }

    private func readKeychainData(account: String) throws -> Data? {
        let query: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: account,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly,
            kSecReturnData as String: true,
            kSecMatchLimit as String: kSecMatchLimitOne
        ]

        var result: AnyObject?
        let status = SecItemCopyMatching(query as CFDictionary, &result)

        switch status {
        case errSecSuccess:
            return result as? Data
        case errSecItemNotFound:
            return nil
        default:
            throw BankingError.encryptionFailure
        }
    }

    private func writeKeychainData(_ data: Data, account: String) throws {
        let baseQuery: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: account
        ]

        SecItemDelete(baseQuery as CFDictionary)

        let addQuery: [String: Any] = [
            kSecClass as String: kSecClassGenericPassword,
            kSecAttrAccount as String: account,
            kSecValueData as String: data,
            kSecAttrAccessible as String: kSecAttrAccessibleWhenUnlockedThisDeviceOnly
        ]

        let status = SecItemAdd(addQuery as CFDictionary, nil)
        guard status == errSecSuccess else {
            throw BankingError.encryptionFailure
        }
    }
}

