public protocol TransactionProcessing {
    func createAccount(
        accountNumberMasked: String,
        type: AccountType,
        openingBalance: Decimal,
        currencyCode: String,
        ownerName: String
    ) throws -> Account

    func fetchAccounts() throws -> [Account]
    func fetchTransactions(for accountID: UUID?) throws -> [Transaction]
    func deposit(amount: Decimal, to accountID: UUID, description: String) throws -> Transaction
    func withdraw(amount: Decimal, from accountID: UUID, description: String) throws -> Transaction
    func transfer(amount: Decimal, from sourceAccountID: UUID, to destinationAccountID: UUID, description: String) throws -> [Transaction]
    func accountSummary() throws -> AccountSummary
}

public final class BankingService: TransactionProcessing {
    private let store: BankingStoring
    private let lock = NSLock()

    public init(store: BankingStoring) {
        self.store = store
    }

    public func createAccount(
        accountNumberMasked: String,
        type: AccountType,
        openingBalance: Decimal,
        currencyCode: String,
        ownerName: String
    ) throws -> Account {
        guard openingBalance >= 0, !currencyCode.isEmpty, !ownerName.isEmpty, !accountNumberMasked.isEmpty else {
            throw BankingError.invalidInput
        }

        lock.lock()
        defer { lock.unlock() }

        var accounts = try store.loadAccounts()
        let account = Account(
            accountNumberMasked: accountNumberMasked,
            type: type,
            balance: openingBalance,
            currencyCode: currencyCode.uppercased(),
            ownerName: ownerName
        )
        accounts.append(account)
        try store.saveAccounts(accounts)
        return account
    }

    public func fetchAccounts() throws -> [Account] {
        lock.lock()
        defer { lock.unlock() }
        return try store.loadAccounts().sorted { $0.updatedAt > $1.updatedAt }
    }

    public func fetchTransactions(for accountID: UUID? = nil) throws -> [Transaction] {
        lock.lock()
        defer { lock.unlock() }
        let transactions = try store.loadTransactions()
        let filtered = accountID == nil ? transactions : transactions.filter { $0.accountID == accountID }
        return filtered.sorted { $0.createdAt > $1.createdAt }
    }

    public func deposit(amount: Decimal, to accountID: UUID, description: String) throws -> Transaction {
        guard amount > 0 else { throw BankingError.invalidAmount }

        lock.lock()
        defer { lock.unlock() }

        var accounts = try store.loadAccounts()
        var transactions = try store.loadTransactions()

        guard let index = accounts.firstIndex(where: { $0.id == accountID }) else {
            throw BankingError.accountNotFound
        }

        let newBalance = accounts[index].balance + amount
        accounts[index] = accounts[index].applying(balance: newBalance)

        let transaction = Transaction(
            accountID: accountID,
            type: .deposit,
            amount: amount,
            description: description
        )

        transactions.append(transaction)
        try store.saveAccounts(accounts)
        try store.saveTransactions(transactions)
        return transaction
    }

    public func withdraw(amount: Decimal, from accountID: UUID, description: String) throws -> Transaction {
        guard amount > 0 else { throw BankingError.invalidAmount }

        lock.lock()
        defer { lock.unlock() }

        var accounts = try store.loadAccounts()
        var transactions = try store.loadTransactions()

        guard let index = accounts.firstIndex(where: { $0.id == accountID }) else {
            throw BankingError.accountNotFound
        }

        let currentBalance = accounts[index].balance
        guard currentBalance >= amount else {
            throw BankingError.insufficientFunds
        }

        let newBalance = currentBalance - amount
        accounts[index] = accounts[index].applying(balance: newBalance)

        let transaction = Transaction(
            accountID: accountID,
            type: .withdrawal,
            amount: amount,
            description: description
        )

        transactions.append(transaction)
        try store.saveAccounts(accounts)
        try store.saveTransactions(transactions)
        return transaction
    }

    public func transfer(amount: Decimal, from sourceAccountID: UUID, to destinationAccountID: UUID, description: String) throws -> [Transaction] {
        guard amount > 0, sourceAccountID != destinationAccountID else {
            throw BankingError.invalidInput
        }

        lock.lock()
        defer { lock.unlock() }

        var accounts = try store.loadAccounts()
        var transactions = try store.loadTransactions()

        guard let sourceIndex = accounts.firstIndex(where: { $0.id == sourceAccountID }),
              let destinationIndex = accounts.firstIndex(where: { $0.id == destinationAccountID }) else {
            throw BankingError.accountNotFound
        }

        let source = accounts[sourceIndex]
        let destination = accounts[destinationIndex]

        guard source.currencyCode == destination.currencyCode else {
            throw BankingError.currencyMismatch
        }

        guard source.balance >= amount else {
            throw BankingError.insufficientFunds
        }

        accounts[sourceIndex] = source.applying(balance: source.balance - amount)
        accounts[destinationIndex] = destination.applying(balance: destination.balance + amount)

        let reference = UUID().uuidString
        let outTransaction = Transaction(
            accountID: sourceAccountID,
            type: .transferOut,
            amount: amount,
            description: description,
            reference: reference
        )
        let inTransaction = Transaction(
            accountID: destinationAccountID,
            type: .transferIn,
            amount: amount,
            description: description,
            reference: reference
        )

        transactions.append(outTransaction)
        transactions.append(inTransaction)

        try store.saveAccounts(accounts)
        try store.saveTransactions(transactions)
        return [outTransaction, inTransaction]
    }

    public func accountSummary() throws -> AccountSummary {
        lock.lock()
        defer { lock.unlock() }

        let accounts = try store.loadAccounts()
        let balances = accounts.reduce(into: [String: Decimal]()) { result, account in
            result[account.currencyCode, default: 0] += account.balance
        }

        return AccountSummary(
            totalBalanceByCurrency: balances,
            accounts: accounts.sorted { $0.updatedAt > $1.updatedAt }
        )
    }
}

