public struct AccountBalanceViewData: Equatable {
    public let accountID: UUID
    public let title: String
    public let subtitle: String
    public let formattedBalance: String
}

public final class AccountsViewModel {
    private let service: TransactionProcessing
    private let formatter = CurrencyFormatter()

    public init(service: TransactionProcessing) {
        self.service = service
    }

    public func loadBalances() throws -> [AccountBalanceViewData] {
        let accounts = try service.fetchAccounts()
        return accounts.map {
            AccountBalanceViewData(
                accountID: $0.id,
                title: "\($0.ownerName) • \($0.type.rawValue.capitalized)",
                subtitle: $0.accountNumberMasked,
                formattedBalance: formatter.string(from: $0.balance, currencyCode: $0.currencyCode)
            )
        }
    }

    public func totalBalancesDisplay() throws -> [String] {
        let summary = try service.accountSummary()
        return summary.totalBalanceByCurrency
            .sorted { $0.key < $1.key }
            .map { formatter.string(from: $0.value, currencyCode: $0.key) }
    }
}

// MARK: - Utilities

public struct CurrencyFormatter {
    public init() {}

    public func string(from amount: Decimal, currencyCode: String) -> String {
        let formatter = NumberFormatter()
        formatter.numberStyle = .currency
        formatter.currencyCode = currencyCode
        formatter.maximumFractionDigits = 2
        formatter.minimumFractionDigits = 2
        return formatter.string(from: amount as NSDecimalNumber) ?? "\(currencyCode) \(amount)"
    }
}

